--
-- Triggers `m_event_session`
--
DELIMITER $$
CREATE TRIGGER `update_attendance_on_session_change` AFTER UPDATE ON `m_event_session` FOR EACH ROW BEGIN
    -- Only proceed if start_time, end_time, start_date, or end_date changed
    IF OLD.start_time != NEW.start_time OR 
       OLD.end_time != NEW.end_time OR 
       OLD.start_date != NEW.start_date OR 
       OLD.end_date != NEW.end_date THEN
       
        -- Update attendance statuses for affected students (preserve 'present' status)
        UPDATE attendance a
        INNER JOIN m_guest g ON a.m_guest_id = g.id AND a.m_event_id = g.event_id
        SET 
            a.status = CASE 
                WHEN a.status = 'present' THEN 'present'  -- Never change present status
                WHEN NOW() < CONCAT(NEW.start_date, ' ', NEW.start_time) THEN 'pending'
                WHEN NOW() >= CONCAT(NEW.start_date, ' ', NEW.start_time) 
                     AND NOW() <= CONCAT(NEW.end_date, ' ', NEW.end_time) THEN 'none'
                ELSE 'absent'
            END,
            a.scanned_time = CASE 
                WHEN a.status != 'present' AND 
                     NOW() > CONCAT(NEW.end_date, ' ', NEW.end_time) THEN 
                     CONCAT(NEW.end_date, ' ', NEW.end_time)
                ELSE a.scanned_time
            END
        WHERE g.event_id = NEW.m_event_id 
          AND g.session = NEW.session;
          
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `update_attendance_on_session_insert` AFTER INSERT ON `m_event_session` FOR EACH ROW BEGIN
    -- Update attendance statuses for students in this new session
    UPDATE attendance a
    INNER JOIN m_guest g ON a.m_guest_id = g.id AND a.m_event_id = g.event_id
    SET 
        a.status = CASE 
            WHEN a.status = 'present' THEN 'present'  -- Never change present status
            WHEN NOW() < CONCAT(NEW.start_date, ' ', NEW.start_time) THEN 'pending'
            WHEN NOW() >= CONCAT(NEW.start_date, ' ', NEW.start_time) 
                 AND NOW() <= CONCAT(NEW.end_date, ' ', NEW.end_time) THEN 'none'
            ELSE 'absent'
        END,
        a.scanned_time = CASE 
            WHEN a.status != 'present' AND 
                 NOW() > CONCAT(NEW.end_date, ' ', NEW.end_time) THEN 
                 CONCAT(NEW.end_date, ' ', NEW.end_time)
            ELSE a.scanned_time
        END
    WHERE g.event_id = NEW.m_event_id 
      AND g.session = NEW.session;
END
$$
DELIMITER ;

